function restoreArray(adjacentPairs) {
    const graph = new Map();
    for (const pair of adjacentPairs) {
        if (!graph.has(pair[0])) {
            graph.set(pair[0], []);
        }
        if (!graph.has(pair[1])) {
            graph.set(pair[1], []);
        }
        graph.get(pair[0]).push(pair[1]);
        graph.get(pair[1]).push(pair[0]);
    }
    const n = graph.size;
    const nums = Array(n);
    for (const [key, nodes] of graph.entries()) {
        if (nodes.length === 1) {
            nums[0] = key;
            break;
        }
    }

    nums[1] = graph.get(nums[0])[0];
    for (let i = 2; i < n; i++) {
        const nodes = graph.get(nums[i - 1]);
        nums[i] = nums[i-2] === nodes[0] ? nodes[1] : nodes[0];
    }
    return nums;
}
```

    1. Create a graph represented by a hash map (or dictionary in Python) to store the adjacent nodes for each node.
2. Iterate through the given adjacent pairs and update the graph by adding the corresponding adjacent nodes.
3. Iterate through the graph and find a node with only one adjacent node (i.e., the first or last element of the original array), and set it as the first element of the resulting array.
4. Starting from the second element of the resulting array, loop through and fill in the remaining elements based on the graph. For each element, choose the adjacent node that does not equal the previous element of the resulting array.
5. Return the resulting array.

